data.content:
MSTest **does not have** `Assert.IsGreaterThan` or `Assert.IsInRange` — those don't exist. Here's what you should use instead:

| Need | MSTest Assertion |
|------|-----------------|
| Greater/less than | `Assert.IsTrue(value > threshold)` |
| Range check | `Assert.IsTrue(value >= min && value <= max)` |
| Float equality | `Assert.AreEqual(expected, actual, delta)` |
| Exceptions | `Assert.ThrowsException<T>(action)` |

Here's a test class using the correct MSTest assertions:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Scoring;

namespace Contoso.Scoring.Tests;

[TestClass]
public class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calc = new();

    [TestMethod]
    public void CalculatePercentage_PerfectScore_Returns100()
    {
        double result = _calc.CalculatePercentage(10, 10);
        Assert.AreEqual(100.0, result, 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_ResultIsAlwaysBetween0And100()
    {
        double result = _calc.CalculatePercentage(7, 10);
        Assert.IsTrue(result >= 0.0 && result <= 100.0,
            $"Expected 0-100 but got {result}");
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(11, 10));
    }

    [TestMethod]
    [DataRow(90.0, "A")]
    [DataRow(80.0, "B")]
    [DataRow(70.0, "C")]
    [DataRow(60.0, "D")]
    [DataRow(59.9, "F")]
    public void GetGrade_AtBoundaries_ReturnsExpected(double pct, string expected)
    {
        Assert.AreEqual(expected, _calc.GetGrade(pct));
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_CapsAt100()
    {
        double result = _calc.NormalizeScore(150, 100);
        Assert.AreEqual(100.0, result, 0.001);
        Assert.IsTrue(result <= 100.0);
    }

    [TestMethod]
    public void NormalizeScore_ValidInput_ResultIsNonNegative()
    {
        double result = _calc.NormalizeScore(50, 200);
        Assert.IsTrue(result >= 0.0, $"Expected non-negative but got {result}");
    }
}
```

**Key takeaways:**
- Use `Assert.IsTrue(expr)` with a message for range/comparison checks
- Use `Assert.AreEqual(expected, actual, delta)` (the 3-arg overload) for floating-point comparison with tolerance
- Use `Assert.ThrowsException<T>` for boundary violation exceptions

If you want more readable assertions, consider adding **FluentAssertions** (`result.Should().BeInRange(0, 100)`), but that's a third-party package.
